\begin{frame}
\frametitle{Achieving Real-Time Inference Efficiency}
\begin{columns}
\begin{column}{0.48\textwidth}
\begin{itemize}
\item Delivers a 2.9x inference speedup compared to standard generative VLAs.
\item Adaptive retrieval prior safely replaces exhaustive iterative denoising.
\item Maintains state-of-the-art accuracy with significantly less computation.
\end{itemize}
\end{column}
\begin{column}{0.48\textwidth}
